{
  "plan_version": "1.1",
  "lane_id": "PG-004",
  "design": {
    "principle": "Surgical edits only — no restructuring. Additive on dirty files. Keep backward compatibility via optional params.",
    "files_created": [],
    "files_modified": [
      "packages/opencode/src/effect/database-config.ts",
      "packages/opencode/src/storage/db.pg.ts",
      "packages/opencode/src/storage/pg-pool.ts",
      "packages/opencode/src/storage/adapter.ts",
      "packages/opencode/test/storage/pg-pool.pg.test.ts"
    ],
    "files_deferred": [
      "packages/opencode/src/server/routes/instance/httpapi/handlers/global.ts — health endpoint enhancement deferred"
    ]
  },
  "changes": [
    {
      "id": "fix-0-ispgpool-public",
      "file": "packages/opencode/src/storage/pg-pool.ts",
      "description": "Make isRetryableError public static so it can be unit-tested directly. It's a pure classification function (auth vs transient errors), not an implementation detail.",
      "before": "private static isRetryableError(cause: unknown): boolean {",
      "after": "static isRetryableError(cause: unknown): boolean {",
      "impact": {
        "affected_files": ["packages/opencode/src/storage/pg-pool.ts"],
        "tests_to_run": ["packages/opencode/test/storage/pg-pool.pg.test.ts"]
      },
      "risks": ["External code could now call PgPool.isRetryableError — benign, it's a pure classification function"],
      "validation": "bun run typecheck"
    },
    {
      "id": "fix-1-database-config",
      "file": "packages/opencode/src/effect/database-config.ts",
      "description": "Add missing pool config env vars to DatabaseConfig.Service",
      "before": "Three fields: url, ssl, poolSize",
      "after": "Seven fields: url, ssl, poolSize, poolMin, connectionTimeoutMs, idleTimeoutMs, maxRetries",
      "diff": "Add 4 new Config.number() lines inside the Service class definition",
      "impact": {
        "affected_files": ["packages/opencode/src/effect/database-config.ts"],
        "tests_to_run": ["None directly — config validated via integration tests"]
      },
      "risks": ["New env var names must match infra. Mismatch is silent (defaults apply, which are production-sensible: 1 min, 5s timeout, 30s idle, 3 retries)"],
      "validation": "bun run typecheck"
    },
    {
      "id": "fix-2-db-pg",
      "file": "packages/opencode/src/storage/db.pg.ts",
      "description": "Add InitOptions interface, update init() with optional pool config, add initFromPool() bridge",
      "before": "export function init(connectionString: string, ssl?: boolean): PgClient — Pool created with hardcoded defaults. No initFromPool().",
      "after": "export interface InitOptions { poolSize?: number; poolMin?: number; connectionTimeoutMs?: number; idleTimeoutMs?: number }\nexport function init(connectionString: string, ssl?: boolean, options?: InitOptions): PgClient — Pool creation uses options ?? defaults.\nexport function initFromPool(pool: PgPool): NodePgDatabase — creates Drizzle client from PgPool.getPool().\nNew import: import type { PgPool } from \"./pg-pool\"",
      "impact": {
        "affected_files": ["packages/opencode/src/storage/db.pg.ts"],
        "transitively_affected": ["packages/opencode/src/storage/adapter.ts (imports from #db)"],
        "tests_to_run": ["packages/opencode/test/storage/pg-pool.pg.test.ts"]
      },
      "risks": [
        "PGlite path ignores options entirely — intentional, safe",
        "#db alias backward compat: InitOptions is new type export, initFromPool new function — additive only",
        "Circular dep: db.pg → pg-pool. pg-pool does NOT import from db.pg — safe"
      ],
      "validation": "bun run typecheck"
    },
    {
      "id": "fix-3-adapter",
      "file": "packages/opencode/src/storage/adapter.ts",
      "description": "Thread InitOptions through makePgAdapter, PgAdapter, and defaultLayer",
      "changes": [
        {
          "target": "Import",
          "before": "import { init as initPg } from \"#db\"",
          "after": "import { init as initPg, type InitOptions } from \"#db\""
        },
        {
          "target": "makePgAdapter",
          "before": "function makePgAdapter(url: string, ssl: boolean): Interface",
          "after": "function makePgAdapter(url: string, ssl: boolean, options?: InitOptions): Interface"
        },
        {
          "target": "makePgAdapter body",
          "before": "const client = initPg(url, ssl)",
          "after": "const client = initPg(url, ssl, options)"
        },
        {
          "target": "PgAdapter export",
          "before": "export const PgAdapter: (url: string, ssl?: boolean) => Layer.Layer<Service> = (url, ssl = true) => Layer.effect(Service, Effect.sync(() => makePgAdapter(url, ssl)))",
          "after": "export const PgAdapter: (url: string, ssl?: boolean, options?: InitOptions) => Layer.Layer<Service> = (url, ssl = true, options) => Layer.effect(Service, Effect.sync(() => makePgAdapter(url, ssl, options)))"
        },
        {
          "target": "defaultLayer body (line ~366)",
          "before": "const adapter = makePgAdapter(url, config.ssl)",
          "after": "const adapter = makePgAdapter(url, config.ssl, { poolSize: config.poolSize, poolMin: config.poolMin, connectionTimeoutMs: config.connectionTimeoutMs, idleTimeoutMs: config.idleTimeoutMs })"
        }
      ],
      "impact": {
        "affected_files": ["packages/opencode/src/storage/adapter.ts"],
        "transitively_affected": ["Consumers of DatabaseAdapter.defaultLayer or PgAdapter — no breakage, options is optional"],
        "tests_to_run": ["packages/opencode/test/storage/adapter.pg.test.ts"]
      },
      "risks": [
        "adapter.ts has STAGED changes — preflight before editing, be additive",
        "PgAdapter is public export — third param is optional, backward compatible"
      ],
      "validation": "bun run typecheck && bun run test packages/opencode/test/storage/adapter.pg.test.ts"
    },
    {
      "id": "fix-4-tests",
      "file": "packages/opencode/test/storage/pg-pool.pg.test.ts",
      "description": "Enhance existing test file with isRetryableError classification, healthCheck true path, close drain, config default values tests",
      "additions": [
        "isRetryableError — auth error (28P01) returns false (via new public static access)",
        "isRetryableError — SSL handshake error returns false",
        "isRetryableError — ENOTFOUND returns true",
        "isRetryableError — ECONNREFUSED returns true",
        "isRetryableError — ETIMEDOUT returns true",
        "isRetryableError — generic Error returns true (default)",
        "isRetryableError — non-Error input (string, null, object) returns true",
        "PgPool config — uses defaults when not specified (verify defaults exist in PgPoolConfig defaults)",
        "healthCheck — returns true when pool is connected (test with PgPool.create + valid config)",
        "close — drains pool gracefully (test with PgPool.create + valid config)",
        "initFromPool — creates Drizzle client from PgPool (import from #db)"
      ],
      "impact": {
        "affected_files": ["packages/opencode/test/storage/pg-pool.pg.test.ts"],
        "tests_to_run": ["packages/opencode/test/storage/pg-pool.pg.test.ts"]
      },
      "risks": [
        "isRetryableError tests are pure unit tests — no PG needed, fast and reliable",
        "healthCheck true / close tests need real PgPool.create() which requires actual PG — guard with isRealPg() pattern or use PGlite",
        "For isRetryableError tests: errors are created as `new Error(...)` — tests are synchronous, no connection needed",
        "Config default test: verify that PgPool.create() with minimal config creates pool with expected defaults — needs actual PG or verification via PgPoolConfig type"
      ],
      "validation": "bun run test packages/opencode/test/storage/pg-pool.pg.test.ts"
    }
  ],
  "apply_order": ["fix-0-ispgpool-public", "fix-1-database-config", "fix-2-db-pg", "fix-3-adapter", "fix-4-tests"],
  "rollback_plan": "Reverse order: revert fix-4-tests, fix-3-adapter, fix-2-db-pg, fix-1-database-config, fix-0-ispgpool-public. Each file is independently revertible.",
  "risk_summary": {
    "high": [
      "adapter.ts has staged changes — preflight required before edit"
    ],
    "medium": [
      "healthCheck true and close tests need live PgPool — guard with isRealPg()",
      "Circular dep db.pg → pg-pool — confirmed one-directional, safe"
    ],
    "low": [
      "All init/pool changes are optional-param additive — 100% backward compatible",
      "PGlite path ignores InitOptions — correct behavior"
    ]
  },
  "out_of_scope": {
    "health_endpoint": "/global/health still returns {healthy: true, version} — needs DI of pool for real probe. Deferred.",
    "migration_gap": "migration-pg/ has 1 migration vs migration/ has 20 — noted in previous findings."
  }
}
